import React, { useState } from 'react';
import './UploadContent.css';

const UploadContent = () => {
  const [contentType, setContentType] = useState('manga');
  const [formData, setFormData] = useState({
    title: '',
    author: '',
    description: '',
    category: 'Манга',
    tags: '',
    chapters: '',
    cover: null
  });
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFormData(prev => ({
        ...prev,
        cover: file
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setUploading(true);
    
    // Simulate upload progress
    const interval = setInterval(() => {
      setUploadProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return prev + 10;
      });
    }, 200);
    
    // Simulate API call
    setTimeout(() => {
      clearInterval(interval);
      setUploading(false);
      setUploadProgress(0);
      alert('Контент успешно загружен!');
      setFormData({
        title: '',
        author: '',
        description: '',
        category: 'Манга',
        tags: '',
        chapters: '',
        cover: null
      });
    }, 3000);
  };

  return (
    <div className="upload-content">
      <h2>Загрузка контента</h2>
      
      <div className="content-type-tabs">
        <button 
          className={`type-tab ${contentType === 'manga' ? 'active' : ''}`}
          onClick={() => setContentType('manga')}
        >
          <i className="fas fa-book"></i>
          Манга/Манхва
        </button>
        <button 
          className={`type-tab ${contentType === 'video' ? 'active' : ''}`}
          onClick={() => setContentType('video')}
        >
          <i className="fas fa-video"></i>
          Видео
        </button>
      </div>
      
      <form onSubmit={handleSubmit} className="upload-form">
        <div className="form-row">
          <div className="form-group">
            <label>Название *</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="Введите название"
              required
            />
          </div>
          
          <div className="form-group">
            <label>Автор *</label>
            <input
              type="text"
              name="author"
              value={formData.author}
              onChange={handleChange}
              placeholder="Введите автора"
              required
            />
          </div>
        </div>
        
        <div className="form-row">
          <div className="form-group">
            <label>Категория *</label>
            <select
              name="category"
              value={formData.category}
              onChange={handleChange}
              required
            >
              <option value="Манга">Манга</option>
              <option value="Манхва">Манхва</option>
              <option value="Маньхуа">Маньхуа</option>
              <option value="OEL-манга">OEL-манга</option>
              <option value="Руманга">Руманга</option>
              <option value="Комикс">Комикс</option>
            </select>
          </div>
          
          {contentType === 'manga' && (
            <div className="form-group">
              <label>Количество глав</label>
              <input
                type="number"
                name="chapters"
                value={formData.chapters}
                onChange={handleChange}
                placeholder="Введите количество глав"
              />
            </div>
          )}
        </div>
        
        <div className="form-group">
          <label>Описание *</label>
          <textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
            placeholder="Введите описание"
            rows="4"
            required
          />
        </div>
        
        <div className="form-group">
          <label>Теги (через запятую)</label>
          <input
            type="text"
            name="tags"
            value={formData.tags}
            onChange={handleChange}
            placeholder="Например: экшен, фэнтези, драма"
          />
        </div>
        
        <div className="form-group">
          <label>Обложка *</label>
          <div className="file-upload">
            <label className="upload-area">
              {formData.cover ? (
                <div className="file-preview">
                  <i className="fas fa-file-image"></i>
                  <span>{formData.cover.name}</span>
                </div>
              ) : (
                <>
                  <i className="fas fa-cloud-upload-alt"></i>
                  <span>Нажмите для загрузки обложки</span>
                  <span className="file-types">PNG, JPG, WebP (рекомендуется 400x600)</span>
                </>
              )}
              <input
                type="file"
                accept="image/*"
                onChange={handleFileChange}
                hidden
              />
            </label>
          </div>
        </div>
        
        {contentType === 'video' && (
          <div className="form-group">
            <label>Видео файл</label>
            <div className="file-upload">
              <label className="upload-area">
                <i className="fas fa-video"></i>
                <span>Нажмите для загрузки видео</span>
                <span className="file-types">MP4, WebM, MKV (макс. 2GB)</span>
                <input
                  type="file"
                  accept="video/*"
                  hidden
                />
              </label>
            </div>
          </div>
        )}
        
        {uploading && (
          <div className="upload-progress">
            <div className="progress-bar">
              <div 
                className="progress-fill" 
                style={{ width: `${uploadProgress}%` }}
              ></div>
            </div>
            <span className="progress-text">{uploadProgress}%</span>
          </div>
        )}
        
        <button 
          type="submit" 
          className="upload-btn"
          disabled={uploading}
        >
          {uploading ? (
            <>
              <i className="fas fa-spinner fa-spin"></i>
              Загрузка...
            </>
          ) : (
            <>
              <i className="fas fa-upload"></i>
              Загрузить контент
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default UploadContent;
